import{r as n,o as s,c as a,a as e,F as p,d as t,b as c}from"./app.446a9310.js";const l={},o=t('<h1 id="入门" tabindex="-1"><a class="header-anchor" href="#入门" aria-hidden="true">#</a> 入门</h1><h2 id="安装" tabindex="-1"><a class="header-anchor" href="#安装" aria-hidden="true">#</a> 安装</h2><p>确保安装了 npx（npx 在 NPM 版本 5.2.0 默认安装了）：</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code>npx create-nuxt-app <span class="token operator">&lt;</span>项目名<span class="token operator">&gt;</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div>',4),r=c("或者用 yarn ："),u=t('<div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token function">yarn</span> create nuxt-app <span class="token operator">&lt;</span>项目名<span class="token operator">&gt;</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><h2 id="目录结构" tabindex="-1"><a class="header-anchor" href="#目录结构" aria-hidden="true">#</a> 目录结构</h2><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code>assets <span class="token comment">// 用于组织未编译的静态资源如 LESS、SASS 或 JavaScript。</span>\ncomponents <span class="token comment">// 用于组织应用的 Vue.js 组件。</span>\nlayouts <span class="token comment">// 用于组织应用的布局组件。</span>\nmiddleware <span class="token comment">// 用于存放应用的中间件。</span>\npages <span class="token comment">// 用于组织应用的路由及视图。</span>\nplugins <span class="token comment">// 用于组织那些需要在 根vue.js应用 实例化之前需要运行的 Javascript 插件。</span>\n<span class="token keyword">static</span> <span class="token comment">// 用于存放应用的静态文件。</span>\nstore <span class="token comment">// 用于组织应用的 Vuex 状态树 文件。</span>\nnuxt<span class="token punctuation">.</span>config<span class="token punctuation">.</span>js <span class="token comment">// 用于组织 Nuxt.js 应用的个性化配置，以便覆盖默认配置。</span>\n<span class="token keyword">package</span><span class="token punctuation">.</span>json <span class="token comment">//用于描述应用的依赖关系和对外暴露的脚本接口。</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br></div></div><h2 id="别名" tabindex="-1"><a class="header-anchor" href="#别名" aria-hidden="true">#</a> 别名</h2><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code><span class="token operator">~</span> <span class="token operator">===</span> srcDir\n@ <span class="token operator">===</span> srcDir\n\n<span class="token operator">~</span><span class="token operator">~</span> <span class="token operator">===</span> rootDir\n@@ <span class="token operator">===</span> rootDir\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>默认情况下，srcDir 和 rootDir 相同。</p><div class="custom-container tip"><p class="custom-container-title">TIP</p><p>提示：在您的 vue 模板中，如果你需要引入 <code>assets</code> 或者 <code>static</code> 目录，使用 <code>~/assets/your_image.png</code> 和 <code>~/static/your_image.png</code> 方式。</p></div><h2 id="路由" tabindex="-1"><a class="header-anchor" href="#路由" aria-hidden="true">#</a> 路由</h2><p>Nuxt.js 依据 <code>pages</code> 目录结构自动生成 <code>vue-router</code> 模块的路由配置。</p><div class="custom-container tip"><p class="custom-container-title">TIP</p><p>要在页面之间使用路由，我们建议使用 <code>&lt;nuxt-link&gt;</code> 标签。</p></div><p>例如：</p><div class="language-vue ext-vue line-numbers-mode"><pre class="language-vue"><code><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>template</span><span class="token punctuation">&gt;</span></span>\n  <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>nuxt-link</span> <span class="token attr-name">to</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>/<span class="token punctuation">&quot;</span></span><span class="token punctuation">&gt;</span></span>首页<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>nuxt-link</span><span class="token punctuation">&gt;</span></span>\n<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>template</span><span class="token punctuation">&gt;</span></span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><h3 id="基础路由" tabindex="-1"><a class="header-anchor" href="#基础路由" aria-hidden="true">#</a> 基础路由</h3><p>假设 <code>pages</code> 的目录结构如下：</p><div class="language-markdown ext-md line-numbers-mode"><pre class="language-markdown"><code>pages/\n--| user/\n-----| index.vue\n-----| one.vue\n--| index.vue\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>那么，Nuxt.js 自动生成的路由配置如下：</p><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code>router<span class="token operator">:</span> <span class="token punctuation">{</span>\n  routes<span class="token operator">:</span> <span class="token punctuation">[</span>\n    <span class="token punctuation">{</span>\n      name<span class="token operator">:</span> <span class="token string">&#39;index&#39;</span><span class="token punctuation">,</span>\n      path<span class="token operator">:</span> <span class="token string">&#39;/&#39;</span><span class="token punctuation">,</span>\n      component<span class="token operator">:</span> <span class="token string">&#39;pages/index.vue&#39;</span>\n    <span class="token punctuation">}</span><span class="token punctuation">,</span>\n    <span class="token punctuation">{</span>\n      name<span class="token operator">:</span> <span class="token string">&#39;user&#39;</span><span class="token punctuation">,</span>\n      path<span class="token operator">:</span> <span class="token string">&#39;/user&#39;</span><span class="token punctuation">,</span>\n      component<span class="token operator">:</span> <span class="token string">&#39;pages/user/index.vue&#39;</span>\n    <span class="token punctuation">}</span><span class="token punctuation">,</span>\n    <span class="token punctuation">{</span>\n      name<span class="token operator">:</span> <span class="token string">&#39;user-one&#39;</span><span class="token punctuation">,</span>\n      path<span class="token operator">:</span> <span class="token string">&#39;/user/one&#39;</span><span class="token punctuation">,</span>\n      component<span class="token operator">:</span> <span class="token string">&#39;pages/user/one.vue&#39;</span>\n    <span class="token punctuation">}</span>\n  <span class="token punctuation">]</span>\n<span class="token punctuation">}</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br></div></div><h3 id="动态路由" tabindex="-1"><a class="header-anchor" href="#动态路由" aria-hidden="true">#</a> 动态路由</h3><p>在 Nuxt.js 里面定义带参数的动态路由，需要创建对应的以下划线作为前缀的 Vue 文件 或 目录。</p><p>以下目录结构：</p><div class="language-markdown ext-md line-numbers-mode"><pre class="language-markdown"><code>pages/\n--| _slug/\n-----| comments.vue\n-----| index.vue\n--| users/\n-----| _id.vue\n--| index.vue\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>Nuxt.js 生成对应的路由配置表为：</p><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code>router<span class="token operator">:</span> <span class="token punctuation">{</span>\n  routes<span class="token operator">:</span> <span class="token punctuation">[</span>\n    <span class="token punctuation">{</span>\n      name<span class="token operator">:</span> <span class="token string">&#39;index&#39;</span><span class="token punctuation">,</span>\n      path<span class="token operator">:</span> <span class="token string">&#39;/&#39;</span><span class="token punctuation">,</span>\n      component<span class="token operator">:</span> <span class="token string">&#39;pages/index.vue&#39;</span>\n    <span class="token punctuation">}</span><span class="token punctuation">,</span>\n    <span class="token punctuation">{</span>\n      name<span class="token operator">:</span> <span class="token string">&#39;users-id&#39;</span><span class="token punctuation">,</span>\n      path<span class="token operator">:</span> <span class="token string">&#39;/users/:id?&#39;</span><span class="token punctuation">,</span>\n      component<span class="token operator">:</span> <span class="token string">&#39;pages/users/_id.vue&#39;</span>\n    <span class="token punctuation">}</span><span class="token punctuation">,</span>\n    <span class="token punctuation">{</span>\n      name<span class="token operator">:</span> <span class="token string">&#39;slug&#39;</span><span class="token punctuation">,</span>\n      path<span class="token operator">:</span> <span class="token string">&#39;/:slug&#39;</span><span class="token punctuation">,</span>\n      component<span class="token operator">:</span> <span class="token string">&#39;pages/_slug/index.vue&#39;</span>\n    <span class="token punctuation">}</span><span class="token punctuation">,</span>\n    <span class="token punctuation">{</span>\n      name<span class="token operator">:</span> <span class="token string">&#39;slug-comments&#39;</span><span class="token punctuation">,</span>\n      path<span class="token operator">:</span> <span class="token string">&#39;/:slug/comments&#39;</span><span class="token punctuation">,</span>\n      component<span class="token operator">:</span> <span class="token string">&#39;pages/_slug/comments.vue&#39;</span>\n    <span class="token punctuation">}</span>\n  <span class="token punctuation">]</span>\n<span class="token punctuation">}</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br><span class="line-number">23</span><br><span class="line-number">24</span><br></div></div><p>你会发现名称为 users-id 的路由路径带有 :id? 参数，表示该路由是可选的。如果你想将它设置为必选的路由，需要在 users/_id 目录内创建一个 index.vue 文件。</p>',24);l.render=function(t,c){const l=n("Badge");return s(),a(p,null,[o,e("p",null,[r,e(l,{text:"推荐"})]),u],64)};export default l;
